import{_ as t,c as e,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Быстрый старт: запрос квоты ИИ | opencode-mystatus","description":"Изучите установку и использование opencode-mystatus. За 5 минут настройте плагин и выполните первый запрос квоты ИИ-платформы.","frontmatter":{"title":"Быстрый старт: запрос квоты ИИ | opencode-mystatus","sidebarTitle":"Старт","subtitle":"Быстрый старт: запрос квоты ИИ","description":"Изучите установку и использование opencode-mystatus. За 5 минут настройте плагин и выполните первый запрос квоты ИИ-платформы.","order":1},"headers":[],"relativePath":"ru/vbgate/opencode-mystatus/start/index.md","filePath":"ru/vbgate/opencode-mystatus/start/index.md"}'),r={name:"ru/vbgate/opencode-mystatus/start/index.md"};function s(l,a,n,u,d,h){return i(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="быстрыи-старт" tabindex="-1">Быстрый старт <a class="header-anchor" href="#быстрыи-старт" aria-label="Permalink to &quot;Быстрый старт&quot;">​</a></h1><p>Этот раздел поможет вам быстро начать работу с плагином opencode-mystatus — от установки до использования всего за 5 минут.</p><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Рекомендуем изучать в следующем порядке:</p><h3 id="_1-быстрыи-старт" tabindex="-1">1. <a href="./quick-start/">Быстрый старт</a> <a class="header-anchor" href="#_1-быстрыи-старт" aria-label="Permalink to &quot;1. [Быстрый старт](./quick-start/)&quot;">​</a></h3><p>Установите и настройте плагин за 5 минут, выполните первый запрос квоты ИИ-платформы.</p><ul><li>Три способа установки: позвольте ИИ установить, ручная установка, установка из локального файла</li><li>Настройте команду <code>/mystatus</code></li><li>Проверьте успешность установки</li></ul><h3 id="_2-использование-mystatus" tabindex="-1">2. <a href="./using-mystatus/">Использование mystatus</a> <a class="header-anchor" href="#_2-использование-mystatus" aria-label="Permalink to &quot;2. [Использование mystatus](./using-mystatus/)&quot;">​</a></h3><p>Изучите два способа использования: слэш-команды и естественный язык.</p><ul><li>Использование команды <code>/mystatus</code></li><li>Запросы на естественном языке для вызова инструмента mystatus</li><li>Различия между двумя способами и сценарии применения</li></ul><h3 id="_3-понимание-вывода" tabindex="-1">3. <a href="./understanding-output/">Понимание вывода</a> <a class="header-anchor" href="#_3-понимание-вывода" aria-label="Permalink to &quot;3. [Понимание вывода](./understanding-output/)&quot;">​</a></h3><p>Поймите индикатор прогресса, время сброса и формат вывода для нескольких аккаунтов.</p><ul><li>Значение индикатора прогресса: сплошные блоки против пустых блоков</li><li>Циклы лимитов разных платформ (3 часа, 5 часов, ежемесячно)</li><li>Формат вывода при наличии нескольких аккаунтов</li></ul><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><p>Перед началом обучения убедитесь:</p><ul><li>Установлен <a href="https://opencode.ai" target="_blank" rel="noreferrer">OpenCode</a></li><li>Настроены данные аутентификации минимум одной ИИ-платформы (OpenAI, Zhipu AI, Z.ai, GitHub Copilot или Google Cloud)</li></ul><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этого раздела вы можете продолжить изучение <a href="./../platforms/">Функции платформ</a>, чтобы узнать подробности запроса квот разных платформ.</p>',18)])])}const m=t(r,[["render",s]]);export{p as __pageData,m as default};
